import React, { Component } from 'react';
import { BrowserRouter } from 'react-router-dom';
import MyContextProvider from './contexts/MyContextProvider';
import Main from './components/MainComponent';

class App extends Component {
  render() {
    return (
      <MyContextProvider>
        <BrowserRouter>
          <Main />
        </BrowserRouter>
      </MyContextProvider>
    );
  }
}

export default App;
